),
tenant as (
  select '11111111-1111-1111-1111-111111111111'::uuid as tenant_id
),
normalized as (
  select
    trim(parent_category) as parent_category,
    trim(product) as product,
    nullif(trim(sub_category), '') as sub_category,
    nullif(trim(variant_brand), '') as variant_brand,
    nullif(trim(variant_type), '') as variant_type,
    nullif(trim(variant_size_quantity), '') as variant_size_quantity,
    trim(variant_label) as variant_label,
    nullif(trim(top_product_qty), '') as top_product_qty,
    nullif(trim(source_row_id), '') as source_row_id,
    nullif(trim(match_score), '') as match_score
  from (
    select sr.*
    from seed_rows sr
    join (
      select parent_category, product, coalesce(sub_category, '') as sub_category_key
      from seed_rows
      group by parent_category, product, coalesce(sub_category, '')
      order by parent_category, product, coalesce(sub_category, '')
      limit 100
    ) top_products
      on top_products.parent_category = sr.parent_category
     and top_products.product = sr.product
     and top_products.sub_category_key = coalesce(sr.sub_category, '')
  ) seed_rows
),
canon as (
  select
    parent_category,
    product,
    sub_category,
    coalesce(variant_brand, 'Unknown') as variant_brand,
    coalesce(variant_type, 'Unknown') as variant_type,
    coalesce(variant_size_quantity, 'Unknown') as variant_size_quantity,
    variant_label,
    top_product_qty,
    source_row_id,
    match_score,
    lower(regexp_replace(parent_category, '[^a-zA-Z0-9]+', '-', 'g')) as parent_slug,
    lower(regexp_replace(product, '[^a-zA-Z0-9]+', '-', 'g')) as product_slug,
    case when sub_category is null then null else lower(regexp_replace(sub_category, '[^a-zA-Z0-9]+', '-', 'g')) end as sub_slug
  from normalized
),
insert_top as (
  insert into val_dev.catalog_categories(
    tenant_id, parent_id, name, slug, path, depth, is_leaf, sort_order, is_active
  )
  select distinct
    t.tenant_id,
    null::uuid,
    c.parent_category,
    c.parent_slug,
    '/' || c.parent_slug,
    0,
    true,
    0,
    true
  from canon c
  cross join tenant t
  where c.parent_category is not null and c.parent_category <> ''
  on conflict (tenant_id, path)
  do nothing
  returning id
),
insert_mid as (
  insert into val_dev.catalog_categories(
    tenant_id, parent_id, name, slug, path, depth, is_leaf, sort_order, is_active
  )
  select distinct
    t.tenant_id,
    p.id,
    c.product,
    c.product_slug,
    p.path || '/' || c.product_slug,
    1,
    true,
    0,
    true
  from canon c
  cross join tenant t
  join val_dev.catalog_categories p
    on p.tenant_id = t.tenant_id
   and p.parent_id is null
   and p.slug = c.parent_slug
  where c.product is not null and c.product <> ''
  on conflict (tenant_id, path)
  do nothing
  returning id
),
insert_leaf as (
  insert into val_dev.catalog_categories(
    tenant_id, parent_id, name, slug, path, depth, is_leaf, sort_order, is_active
  )
  select distinct
    t.tenant_id,
    m.id,
    c.sub_category,
    c.sub_slug,
    m.path || '/' || c.sub_slug,
    2,
    true,
    0,
    true
  from canon c
  cross join tenant t
  join val_dev.catalog_categories p
    on p.tenant_id = t.tenant_id
   and p.parent_id is null
   and p.slug = c.parent_slug
  join val_dev.catalog_categories m
    on m.tenant_id = t.tenant_id
   and m.parent_id = p.id
   and m.slug = c.product_slug
  where c.sub_category is not null and c.sub_slug is not null and c.sub_slug <> ''
  on conflict (tenant_id, path)
  do nothing
  returning id
)
-- category stage checkpoint removed to avoid partial-run confusion

-- recompute leaf flags
update val_dev.catalog_categories c
set is_leaf = not exists (
  select 1 from val_dev.catalog_categories ch
  where ch.tenant_id = c.tenant_id and ch.parent_id = c.id and ch.is_active = true
)
where c.tenant_id = '11111111-1111-1111-1111-111111111111'::uuid;

