canon as (
  select
    trim(parent_category) as parent_category,
    trim(product) as product,
    nullif(trim(sub_category), '') as sub_category,
    coalesce(nullif(trim(variant_brand), ''), 'Unknown') as variant_brand,
    coalesce(nullif(trim(variant_type), ''), 'Unknown') as variant_type,
    coalesce(nullif(trim(variant_size_quantity), ''), 'Unknown') as variant_size_quantity,
    trim(variant_label) as variant_label,
    nullif(trim(source_row_id), '') as source_row_id,
    lower(regexp_replace(trim(parent_category), '[^a-zA-Z0-9]+', '-', 'g')) as parent_slug,
    lower(regexp_replace(trim(product), '[^a-zA-Z0-9]+', '-', 'g')) as product_slug,
    case when nullif(trim(sub_category), '') is null then null else lower(regexp_replace(trim(sub_category), '[^a-zA-Z0-9]+', '-', 'g')) end as sub_slug
  from (
    select sr.*
    from seed_rows sr
    join (
      select parent_category, product, coalesce(sub_category, '') as sub_category_key
      from seed_rows
      group by parent_category, product, coalesce(sub_category, '')
      order by parent_category, product, coalesce(sub_category, '')
      limit 100
    ) top_products
      on top_products.parent_category = sr.parent_category
     and top_products.product = sr.product
     and top_products.sub_category_key = coalesce(sr.sub_category, '')
  ) seed_rows
),
variant_targets as (
  select
    p.id as product_id,
    c.variant_brand,
    c.variant_type,
    c.variant_size_quantity,
    min(c.variant_label) as variant_label,
    ('VAR-' || upper(substr(md5(
      p.id::text || '|' ||
      coalesce(c.variant_brand, 'Unknown') || '|' ||
      coalesce(c.variant_type, 'Unknown') || '|' ||
      coalesce(c.variant_size_quantity, 'Unknown')
    ), 1, 12))) as sku
  from canon c
  cross join tenant t
  join val_dev.catalog_categories pc
    on pc.tenant_id = t.tenant_id and pc.parent_id is null and pc.slug = c.parent_slug
  join val_dev.catalog_categories leaf
    on leaf.tenant_id = t.tenant_id
   and leaf.slug = coalesce(c.sub_slug, c.product_slug)
   and (
     (c.sub_slug is null and leaf.parent_id = pc.id)
     or
     (c.sub_slug is not null and exists (
       select 1 from val_dev.catalog_categories mid
       where mid.tenant_id = t.tenant_id and mid.parent_id = pc.id and mid.slug = c.product_slug and leaf.parent_id = mid.id
     ))
   )
  join val_dev.catalog_products p
    on p.tenant_id = t.tenant_id
   and p.category_id = leaf.id
   and p.slug = 'prod-' || md5(lower(regexp_replace(c.parent_category || '-' || c.product || coalesce('-' || c.sub_category, ''), '[^a-zA-Z0-9]+', '-', 'g')))
  group by
    p.id,
    c.variant_brand,
    c.variant_type,
    c.variant_size_quantity
)
insert into val_dev.catalog_product_variants(
  tenant_id, product_id, sku, name, status, price, currency_code, pack_size, uom, is_default, is_active
)
select
  t.tenant_id,
  vt.product_id,
  vt.sku,
  vt.variant_label,
  'active',
  null,
  null,
  null,
  null,
  false,
  true
from variant_targets vt
cross join tenant t
on conflict (tenant_id, sku)
do nothing;

